qry:select.qry:xquery:
for $r in sql(' SELECT L.oi_anticipo_ddo, L.f_solicitud, L.f_anticipo, L.n_importe,
L.e_cant_cuotas, L.e_periodo, L.e_quincena, L.l_liquida, L.c_estado FROM LIQ97_ANTICIPOS AS L
WHERE L.oi_per_emp_ddo = {#SOURCE:@oi_per_emp_ddo}
{%? (#DOCUM:@c_estado_anticipo!='') {% AND L.c_estado = {#DOCUM:@c_estado_anticipo} %} {% %} %} ORDER BY f_anticipo DESC ')/ROWS/ROW
